#[tokio::test]
async fn test_rerank_basic_request() {
    let daemon = DaemonProcess::spawn().await.unwrap();
    let client = DaemonClient::with_socket_path(daemon.socket_path.clone());

    let query = "What is machine learning?";
    let documents = vec![
        "Machine learning is a subset of AI".to_string(),
        "The weather is nice today".to_string(),
        "Deep learning uses neural networks".to_string(),
    ];

    let scores = client.rerank(query, &documents, "flashrank").await.unwrap();

    assert_eq!(scores.len(), documents.len());
    tracing::info!(?scores, "Rerank scores received");

    // Verify scores are in valid range [0, 1]
    for (i, score) in scores.iter().enumerate() {
        assert!(*score >= 0.0 && *score <= 1.0, 
            "Score {} out of range: {}", i, score);
    }

    // ML-related docs should score higher than weather doc
    // (This is a soft assertion - models may vary)
    tracing::info!(
        ml_score = scores[0],
        weather_score = scores[1],
        dl_score = scores[2],
        "Score comparison"
    );
}

