### Verbosity Levels
```rust
#[derive(Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Debug, Default)]
pub enum Verbosity {
    Quiet,    // -q: Only errors, no progress
    #[default]
    Normal,   // Default: Normal output
    Verbose,  // -v: Extra details
    Debug,    // -vv: Debug output (enables tracing)
}

impl Verbosity {
    pub fn from_flags(quiet: bool, verbose_count: u8) -> Self {
        if quiet {
            Self::Quiet
        } else {
            match verbose_count {
                0 => Self::Normal,
                1 => Self::Verbose,
                _ => Self::Debug,
            }
        }
    }

    /// Returns the tracing log level for this verbosity
    pub fn log_level(&self) -> tracing::Level {
        match self {
            Self::Quiet => tracing::Level::ERROR,
            Self::Normal => tracing::Level::WARN,
            Self::Verbose => tracing::Level::INFO,
            Self::Debug => tracing::Level::DEBUG,
        }
    }

    /// Returns tracing filter directive string
    pub fn log_filter(&self) -> &'static str {
        match self {
            Self::Quiet => "error",
            Self::Normal => "warn",
            Self::Verbose => "info",
            Self::Debug => "debug",
        }
    }
}

impl Output {
    pub fn with_verbosity(mut self, verbosity: Verbosity) -> Self {
        self.verbosity = verbosity;
        self
    }

    pub fn is_quiet(&self) -> bool {
        self.verbosity == Verbosity::Quiet
    }

    pub fn is_verbose(&self) -> bool {
        self.verbosity >= Verbosity::Verbose
    }

    pub fn is_debug(&self) -> bool {
        self.verbosity >= Verbosity::Debug
    }

    /// Print only if not quiet
    pub fn print_normal(&self, text: &str) {
        if self.verbosity >= Verbosity::Normal {
            self.print(text);
        }
    }

    /// Print only in verbose mode
    pub fn print_verbose(&self, text: &str) {
        if self.is_verbose() {
            if self.is_styled() {
                self.print(&format!("[{}][verbose][/] {}", self.theme.muted, text));
            } else {
                println!("[verbose] {}", text);
            }
        }
    }

    /// Print only in debug mode
    pub fn print_debug(&self, text: &str) {
        if self.is_debug() {
            if self.is_styled() {
                self.print(&format!("[{}][debug][/] {}", self.theme.muted, text));
            } else {
                println!("[debug] {}", text);
            }
        }
    }

    /// Initialize tracing based on verbosity level
    pub fn init_tracing(&self) {
        use tracing_subscriber::EnvFilter;

        let filter = EnvFilter::new(self.verbosity.log_filter());
        tracing_subscriber::fmt()
            .with_env_filter(filter)
            .with_writer(std::io::stderr)
            .init();
    }
}
